const fs = require\('fs'\);
const path = require\('path'\);

// Mapping: directory name → store hook name
const mapping = {
  'dday': 'useDdayWidgetStore',
  'clock': 'useClockStore',
  'analog-clock': 'useAnalogClockStore',
  'mini-calendar': 'useMiniCalendarStore',
  'timeline': 'useTimelineStore',
  'flip-clock': 'useFlipClockStore',
  'time-progress': 'useTimeProgressStore',
  'life-calendar': 'useLifeCalendarStore',
  'reading': 'useReadingStore',
  'goal': 'useGoalStore',
  'pomodoro': 'usePomodoroStore',
  'stopwatch': 'useStopwatchStore',
  'counter': 'useCounterStore',
  'habit': 'useHabitStore',
  'qr-code': 'useQRCodeStore',
  'dice': 'useDiceStore',
  'quote': 'useQuoteStore',
  'banner': 'useBannerStore',
  'bookmark': 'useBookmarkStore',
  'music': 'useMusicStore',
  'weather': 'useWeatherStore',
  'moon-phase': 'useMoonPhaseStore',
  'sticky-note': 'useStickyNoteStore',
  'gradient': 'useGradientStore',
  'typewriter': 'useTypewriterStore',
};

let count = 0;
for \(const [dir, store] of Object.entries\(mapping\)\) {
  const filePath = path.join\('src/app/create', dir, 'page.tsx'\);
  let content = fs.readFileSync\(filePath, 'utf8'\);

  const old = '<EditorActions widgetUrl={widgetUrl} onCopy={handleCopy} onReset={reset} />';
  const replacement = '<EditorActions widgetUrl={widgetUrl} onCopy={handleCopy} onReset={reset} onApplyTheme={\(c\) => ' + store + '.setState\(c\)} />';

  if \(content.includes\(old\)\) {
    content = content.replace\(old, replacement\);
    fs.writeFileSync\(filePath, content\);
    count++;
    console.log\('Updated:', dir\);
  } else {
    console.log\('SKIP \(pattern not found\):', dir\);
  }
}
console.log\('\\\\nTotal updated:', count\);
")

